public class ImmutableDemo {
    public static void main(String[] args) {
        String s = "hello";
        s.toUpperCase();          // WRONG: creates new String, discards it
        System.out.println(s);    // still prints: hello

        s = s.toUpperCase();      // CORRECT: reassign
        System.out.println(s);    // prints: HELLO

        String a = "  spaces  ";
        a.trim();                  // WRONG: original unchanged
        System.out.println("'" + a + "'");       // '  spaces  '

        a = a.trim();              // CORRECT
        System.out.println("'" + a + "'");       // 'spaces'
    }
}

public class StringPoolDemo {
    public static void main(String[] args) {
        String a = "java";
        String b = "java";               // same pool object
        String c = new String("java");   // new heap object
        String d = "ja" + "va";          // compile-time constant → pool

        System.out.println(a == b);       // true  (same pool reference)
        System.out.println(a == c);       // false (different heap object)
        System.out.println(a == d);       // true  ("java" is a compile-time constant)
        System.out.println(a.equals(c));  // true  (same content)

        String x = "ja";
        String y = x + "va";             // runtime concatenation → new object
        System.out.println(a == y);       // false (runtime concat, not interned)
        System.out.println(a.equals(y));  // true
    }
}

public class SubstringDemo {
    public static void main(String[] args) {
        String s = "Programming";
        //          0123456789...
        System.out.println(s.length());          // 11
        System.out.println(s.charAt(0));         // P
        System.out.println(s.charAt(10));        // g
        System.out.println(s.substring(0, 7));   // Program   (indices 0-6)
        System.out.println(s.substring(7));      // ming      (index 7 to end)
        System.out.println(s.substring(3, 3));   // ""        (empty: j==i)
        // s.charAt(11); // throws StringIndexOutOfBoundsException
    }
}

public class StringBuilderDemo {
    public static void main(String[] args) {
        StringBuilder sb = new StringBuilder("Hello");

        sb.append(" World");          // append at end
        System.out.println(sb);       // Hello World

        sb.insert(5, ",");            // insert at index 5
        System.out.println(sb);       // Hello, World

        sb.delete(5, 7);              // delete indices 5 (incl) to 7 (excl)
        System.out.println(sb);       // HelloWorld

        sb.replace(0, 5, "Goodbye");  // replace indices 0-4 with "Goodbye"
        System.out.println(sb);       // GoodbyeWorld

        sb.reverse();
        System.out.println(sb);       // dlroWeybdooG

        sb.deleteCharAt(0);           // delete char at index 0
        System.out.println(sb);       // lroWeybdooG

        System.out.println(sb.length());   // 11
        System.out.println(sb.charAt(0));  // l
        System.out.println(sb.indexOf("W")); // 3

        // Convert back to String
        String result = sb.toString();
        System.out.println(result);   // lroWeybdooG
    }
}

public class PerformanceDemo {
    public static void main(String[] args) {
        // BAD: creates n intermediate String objects
        String bad = "";
        for (int i = 0; i < 5; i++) bad += i; // new String each iteration
        System.out.println(bad); // 01234

        // GOOD: single StringBuilder, O(n) total
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 5; i++) sb.append(i);
        System.out.println(sb.toString()); // 01234

        // Both give the same result but very different performance
        // At n=100000, String loop is ~100x slower
    }
}

