// Write a method that takes a String sentence and returns the sentence
// with the ORDER of words reversed, but each word's characters in
// their original order. Words are separated by single spaces.
// Input:  "The quick brown fox"
// Output: "fox brown quick The"
// Hint: use split(), StringBuilder or array reversal.

sections.solution:
public class ReverseWords {
    public static String reverseWords(String sentence) {
        String[] words = sentence.split(" ");
        StringBuilder sb = new StringBuilder();
        for (int i = words.length - 1; i >= 0; i--) {
            sb.append(words[i]);
            if (i > 0) sb.append(" "); // space between words only
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(reverseWords("The quick brown fox"));
        // Output: fox brown quick The

        System.out.println(reverseWords("Hello World"));
        // Output: World Hello

        System.out.println(reverseWords("single"));
        // Output: single
    }
}
